  // The order:status-changed handler sends to event.order.userId, not an email.
  // Without an email adapter, the notification is stored as 'sent' (in-memory only).
  // We unregister the email adapter for this test to match that behavior.
  notifService.unregisterAdapter('email');

  const event: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  };

  await eventBus.emit(event);

  const history = historyService.getAllHistory();
  expect(history).toHaveLength(1);
  expect(history[0]!.channel).toBe('email');
  expect(history[0]!.status).toBe('sent');
  expect(history[0]!.subject).toContain('Order Update');
});

